on_write:
let res = #{ action: "Allow" };
if !payload.contains("columns") {
    res.action = "Reject";
    res.reason = "Columnar blocks must store data in a columns map";
}
res

on_read:
let res = #{ payload: payload };
res.match_found = true;
res

on_index:
let res = #{ score: 1.0 };
if payload.contains("partition_key") {
    res.partition = payload.partition_key;
}
res
